mapper.select:
SELECT order_id, user_id, lawyer_id, service_type_id, total_amount, status, created_time, updated_time FROM `order` WHERE status = '待接单' AND lawyer_id IS NULL
AND service_type_id = #{serviceTypeId}
ORDER BY created_time DESC

SELECT order_id, user_id, lawyer_id, service_type_id, total_amount, status, created_time, updated_time
FROM `order`
WHERE order_id = #{orderId}

SELECT order_id, user_id, lawyer_id, service_type_id, total_amount, status, created_time, updated_time
FROM `order`
WHERE lawyer_id = #{lawyerId}
  AND status IN ('处理中', '待客户确认', '待评价', '已完成')

    AND status = #{status}

ORDER BY updated_time DESC, created_time DESC

mapper.update:
UPDATE `order`
SET status = #{newStatus}
WHERE order_id = #{orderId}
  AND status = #{currentStatus}
